import React from 'react';

function About({ data }) {
  if (!data) return null;

  return (
    <section id="about" className="py-12 md:py-16 bg-white">
      <div className="max-w-2xl mx-auto px-4">
        <div className="bg-white rounded-2xl shadow-lg p-8">
          <h2 className="text-2xl font-bold text-gray-900 mb-4">About</h2>
          <p className="text-gray-700 leading-relaxed mb-6">
            {data.about}
          </p>
          
          <div className="grid grid-cols-2 gap-4 mt-6">
            <div className="bg-gray-50 rounded-lg p-4">
              <p className="text-xs text-gray-500 font-semibold uppercase mb-1">Location</p>
              <p className="text-gray-900 font-semibold">{data.location}</p>
            </div>
            <div className="bg-gray-50 rounded-lg p-4">
              <p className="text-xs text-gray-500 font-semibold uppercase mb-1">Email</p>
              <a href={`mailto:${data.email}`} className="text-blue-600 font-semibold hover:underline text-sm">
                {data.email}
              </a>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}

export default About;
